import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetimeimport urllib.parse# --- 1. SAYFA AYARLARI VE TAM GİZLİLİK ---st.set_page_config(    page_title="Bostanlı Çözüm VIP - Yönetim",     layout="wide",     page_icon="🏫",    initial_sidebar_state="expanded")# Manage app, Footer ve Header'ı her türlü tarayıcıda GİZLEYEN CSShide_st_style = """            <style>            #MainMenu {visibility: hidden;}            footer {visibility: hidden;}            header {visibility: hidden;}            #stDecoration {display:none;}            [data-testid="stStatusWidget"] {visibility: hidden;}            .stDeployButton {display:none;}            button[title="Manage app"], [data-testid="stManageApp"], .viewerBadge_container__1QS1n {                display: none !important;                visibility: hidden !important;            }            </style>            """st.markdown(hide_st_style, unsafe_allow_html=True)# --- 2. ŞİFRE SİSTEMİ (HEM BUTON HEM ENTER) ---def check_password():    if "password_correct" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")                # Form içinde olması Enter desteği sağlar        with st.form("login_form"):            pwd = st.text_input("Giriş Şifresi", type="password")            submit_button = st.form_submit_button("Sisteme Giriş Yap")                        if submit_button:                if pwd == "cozum35":                    st.session_state["password_correct"] = True                    st.rerun()                else:                    st.error("❌ Hatalı şifre girdiniz.")                st.info("Bostanlı Çözüm VIP Kurs Merkezi - Yetkisiz erişim yasaktır.")        return False    return True# --- EĞER ŞİFRE DOĞRUYSA TÜM PANELİ GÖSTER ---if check_password():    # Google Sheets Bağlantısı    URL = "https://docs.google.com/spreadsheets/d/18BUCCdmATfgHJB1JkM9-T5lhoUaSXes55iMgHVRpOP4/edit?usp=sharing"    conn = st.connection("gsheets", type=GSheetsConnection)    # WhatsApp Link Oluşturucu    def whatsapp_link_olustur(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        encoded_mesaj = urllib.parse.quote(mesaj)        return f"https://wa.me/{tel_str}?text={encoded_mesaj}"    # --- YAN MENÜ ---    st.sidebar.title("🏫 Çözüm VIP Yönetim")    # Sayfa seçimi burada yapılıyor    sayfa = st.sidebar.radio("İşlem Seçiniz:", ["Veli Görüşmeleri", "Kasa İşlemleri", "Kurucu Raporu"])    # ---------------------------------------------------------    # 📝 1. VELİ GÖRÜŞMELERİ SAYFASI    # ---------------------------------------------------------    if sayfa == "Veli Görüşmeleri":        st.header("📞 Veli Görüşme Kayıt")        try:            existing_data = conn.read(spreadsheet=URL, worksheet="gorusmeler", ttl=0)        except:            existing_data = pd.DataFrame(columns=["Tarih", "Ad Soyad", "Telefon", "Konu", "Durum", "Notlar"])                with st.form("veli_formu", clear_on_submit=True):            col1, col2 = st.columns(2)            with col1:                v_ad = st.text_input("Veli / Öğrenci Ad Soyad")                v_tel = st.text_input("Telefon Numarası")            with col2:                v_konu = st.selectbox("Konu", ["Yeni Kayıt", "YKS Hazırlık", "LGS Hazırlık", "Rehberlik", "Taksit", "Diğer"])                v_durum = st.selectbox("Durum", ["Beklemede", "Olumlu", "Kayıt Tamamlandı", "İptal"])            v_not = st.text_area("Görüşme Notları")                        if st.form_submit_button("Kaydı Tamamla"):                if v_ad and v_tel:                    new_row = pd.DataFrame([{                        "Tarih": datetime.now().strftime("%Y-%m-%d %H:%M"),                        "Ad Soyad": v_ad, "Telefon": v_tel, "Konu": v_konu, "Durum": v_durum, "Notlar": v_not                    }])                    updated_df = pd.concat([existing_data, new_row], ignore_index=True)                    conn.update(spreadsheet=URL, worksheet="gorusmeler", data=updated_df)                    st.success(f"✅ {v_ad} başarıyla kaydedildi!")                                        wa_msg = f"Sayın {v_ad}, bugün Bostanlı Çözüm VIP'deki görüşmemiz için teşekkür ederiz."                    st.markdown(f'<a href="{whatsapp_link_olustur(v_tel, wa_msg)}" target="_blank"><button style="background-color:#25D366;color:white;border:none;padding:12px;border-radius:8px;cursor:pointer;font-weight:bold;">🟢 Veliye WhatsApp Mesajı Gönder</button></a>', unsafe_allow_html=True)    # ---------------------------------------------------------    # 💰 2. KASA İŞLEMLERİ SAYFASI    # ---------------------------------------------------------    elif sayfa == "Kasa İşlemleri":        st.header("💰 Gelir / Gider Girişi")        try:            existing_kasa = conn.read(spreadsheet=URL, worksheet="kasa", ttl=0)        except:            existing_kasa = pd.DataFrame(columns=["Tarih", "Tip", "Kategori", "Miktar", "Detay"])        with st.form("kasa_formu", clear_on_submit=True):            k_tip = st.radio("İşlem Türü", ["Gelir (Tahsilat)", "Gider (Ödeme)"])            k_kat = st.selectbox("Kategori", ["Kayıt", "Kitap", "Kira", "Maaş", "Fatura", "Reklam", "Diğer"])            k_tutar = st.number_input("Tutar (TL)", min_value=0.0, step=100.0)            k_detay = st.text_input("İşlem Açıklaması")                        if st.form_submit_button("Kasaya Kaydet"):                new_krow = pd.DataFrame([{                    "Tarih": datetime.now().strftime("%Y-%m-%d"),                    "Tip": k_tip, "Kategori": k_kat, "Miktar": k_tutar, "Detay": k_detay                }])                updated_kasa = pd.concat([existing_kasa, new_krow], ignore_index=True)                conn.update(spreadsheet=URL, worksheet="kasa", data=updated_kasa)                st.success("💰 Kasa başarıyla güncellendi.")    # ---------------------------------------------------------    # 📊 3. KURUCU RAPORU SAYFASI    # ---------------------------------------------------------    elif sayfa == "Kurucu Raporu":        st.header("📊 Günlük Yönetici Raporu")        t_sec = st.date_input("Rapor Tarihi", datetime.now())        t_str = t_sec.strftime("%Y-%m-%d")                try:            g_df = conn.read(spreadsheet=URL, worksheet="gorusmeler", ttl=0)            k_df = conn.read(spreadsheet=URL, worksheet="kasa", ttl=0)                        # Tarihe göre filtreleme            g_bugun = g_df[g_df['Tarih'].str.contains(t_str, na=False)]            k_bugun = k_df[k_df['Tarih'] == t_str]                        gelir = k_bugun[k_bugun['Tip'] == 'Gelir (Tahsilat)']['Miktar'].astype(float).sum()            gider = k_bugun[k_bugun['Tip'] == 'Gider (Ödeme)']['Miktar'].astype(float).sum()                        col1, col2, col3 = st.columns(3)            col1.metric("Görüşme", f"{len(g_bugun)} Adet")            col2.metric("Gelir", f"{gelir:,.0f} TL")            col3.metric("Gider", f"{gider:,.0f} TL")                        rapor_text = f"*📌 BOSTANLI ÇÖZÜM RAPORU ({t_str})*\n\n📞 Görüşme: {len(g_bugun)}\n💰 Gelir: {gelir:,.0f} TL\n💸 Gider: {gider:,.0f} TL\n📈 Net Kasa: {gelir-gider:,.0f} TL"            st.info(rapor_text)                        st.markdown(f'<a href="{whatsapp_link_olustur("905492551912", rapor_text)}" target="_blank"><button style="background-color:#075E54;color:white;border:none;padding:15px;border-radius:10px;cursor:pointer;width:100%;font-weight:bold;">📲 Raporu Kurucuya Gönder</button></a>', unsafe_allow_html=True)        except:            st.error("Rapor oluşturulacak veri henüz mevcut değil.")